<?php require __DIR__.'/brush.php';$p=fn($x,$y)=>['x'=>$x,'y'=>$y];$raw=[[500,520],[450,450],[390,395],[320,370],[250,370],[180,390],[130,450],[120,520],[155,585],[220,635],[300,650],[380,620],[440,570],[500,520],[560,465],[620,410],[700,370],[770,380],[830,420],[870,480],[875,545],[845,610],[790,660],[720,675],[650,655],[585,610],[540,560],[500,520]];$points=array_map(fn($v)=>$p(...$v),$raw);if(Brush::buildRoundedDrawingPath([$p(0,0),$p(100,0),$p(100,100)],40)!=='M 0 0 L 55 0 Q 100 0 100 45 L 100 100')throw new RuntimeException('geometry check failed');if(Brush::sampleAt(Brush::prepareArcLengthPath([$p(0,0),$p(100,0)]),0.5)['angle']!==0.0)throw new RuntimeException('tangent check failed');$input=$argv[1]??'assets/example.webp';$output=$argv[2]??'generated/php.svg';$svg=Brush::renderSvg(file_get_contents($input),'image/webp',1000,1000,$points,'ūü§Ě best friends forever',['magicGradient'=>true]);if(!is_dir(dirname($output)))mkdir(dirname($output),0777,true);file_put_contents($output,$svg);echo"Wrote $output\n";
